// Error types
pyo3::create_exception!(_spikard, RouteError, pyo3::exceptions::PyException);
pyo3::create_exception!(_spikard, ServerError, pyo3::exceptions::PyException);
pyo3::create_exception!(_spikard, DecodeError, pyo3::exceptions::PyException);
pyo3::create_exception!(_spikard, AppError, pyo3::exceptions::PyException);

/// Convert a `spikard::AppError` error to a Python exception.
fn app_error_to_py_err(e: spikard::AppError) -> pyo3::PyErr {
    let msg = e.to_string();
    #[allow(unreachable_patterns)]
    match &e {
        spikard::AppError::Route(..) => RouteError::new_err(msg),
        spikard::AppError::Server(..) => ServerError::new_err(msg),
        spikard::AppError::Decode(..) => DecodeError::new_err(msg),
        _ => AppError::new_err(msg),
    }
}

// Error types
pyo3::create_exception!(_spikard, ExecutionError, pyo3::exceptions::PyException);
pyo3::create_exception!(_spikard, SchemaBuildError, pyo3::exceptions::PyException);
pyo3::create_exception!(_spikard, RequestHandlingError, pyo3::exceptions::PyException);
pyo3::create_exception!(_spikard, SerializationError, pyo3::exceptions::PyException);
pyo3::create_exception!(_spikard, JsonError, pyo3::exceptions::PyException);
pyo3::create_exception!(_spikard, ValidationError, pyo3::exceptions::PyException);
pyo3::create_exception!(_spikard, ParseError, pyo3::exceptions::PyException);
pyo3::create_exception!(_spikard, AuthenticationError, pyo3::exceptions::PyException);
pyo3::create_exception!(_spikard, AuthorizationError, pyo3::exceptions::PyException);
pyo3::create_exception!(_spikard, NotFoundError, pyo3::exceptions::PyException);
pyo3::create_exception!(_spikard, RateLimitExceededError, pyo3::exceptions::PyException);
pyo3::create_exception!(_spikard, InvalidInputError, pyo3::exceptions::PyException);
pyo3::create_exception!(_spikard, ComplexityLimitExceededError, pyo3::exceptions::PyException);
pyo3::create_exception!(_spikard, DepthLimitExceededError, pyo3::exceptions::PyException);
pyo3::create_exception!(_spikard, InternalError, pyo3::exceptions::PyException);
pyo3::create_exception!(_spikard, GraphQLError, pyo3::exceptions::PyException);

/// Convert a `spikard_graphql::GraphQLError` error to a Python exception.
fn graph_q_l_error_to_py_err(e: spikard_graphql::GraphQLError) -> pyo3::PyErr {
    let msg = e.to_string();
    let args = (
        msg.clone(),
        e.status_code(),
        e.is_transient(),
        e.error_type().to_string(),
    );
    #[allow(unreachable_patterns)]
    match &e {
        spikard_graphql::GraphQLError::ExecutionError(..) => ExecutionError::new_err(args),
        spikard_graphql::GraphQLError::SchemaBuildError(..) => SchemaBuildError::new_err(args),
        spikard_graphql::GraphQLError::RequestHandlingError(..) => RequestHandlingError::new_err(args),
        spikard_graphql::GraphQLError::SerializationError(..) => SerializationError::new_err(args),
        spikard_graphql::GraphQLError::JsonError(..) => JsonError::new_err(args),
        spikard_graphql::GraphQLError::ValidationError(..) => ValidationError::new_err(args),
        spikard_graphql::GraphQLError::ParseError(..) => ParseError::new_err(args),
        spikard_graphql::GraphQLError::AuthenticationError(..) => AuthenticationError::new_err(args),
        spikard_graphql::GraphQLError::AuthorizationError(..) => AuthorizationError::new_err(args),
        spikard_graphql::GraphQLError::NotFound(..) => NotFoundError::new_err(args),
        spikard_graphql::GraphQLError::RateLimitExceeded(..) => RateLimitExceededError::new_err(args),
        spikard_graphql::GraphQLError::InvalidInput { .. } => InvalidInputError::new_err(args),
        spikard_graphql::GraphQLError::ComplexityLimitExceeded => ComplexityLimitExceededError::new_err(args),
        spikard_graphql::GraphQLError::DepthLimitExceeded => DepthLimitExceededError::new_err(args),
        spikard_graphql::GraphQLError::InternalError(..) => InternalError::new_err(args),
        _ => GraphQLError::new_err(args),
    }
}

#[pyclass(name = "GraphQLErrorInfo")]
pub struct GraphQLErrorInfo {
    pub status_code: u16,
    pub is_transient: bool,
    pub error_type: String,
}

#[pymethods]
impl GraphQLErrorInfo {
    /// HTTP status code for this error (0 means no associated status).
    #[getter]
    fn status_code(&self) -> u16 {
        self.status_code
    }

    /// Returns `true` if the error is transient and a retry may succeed.
    #[getter]
    fn is_transient(&self) -> bool {
        self.is_transient
    }

    /// Machine-readable error category string for matching and logging.
    #[getter]
    fn error_type(&self) -> String {
        self.error_type.clone()
    }
}

/// Build a `GraphQLErrorInfo` from any exception raised by the `GraphQLError` hierarchy.
///
/// The converter stores `(message, status_code, is_transient, error_type)` in the
/// exception args tuple; this function extracts those values at indices 1–3.
#[pyfunction]
pub fn graph_q_l_error_info(err: pyo3::Bound<'_, pyo3::types::PyAny>) -> GraphQLErrorInfo {
    let args = err.getattr("args").ok();
    GraphQLErrorInfo {
        status_code: args
            .as_ref()
            .and_then(|a| a.get_item(1).ok())
            .and_then(|v| v.extract::<u16>().ok())
            .unwrap_or(0),
        is_transient: args
            .as_ref()
            .and_then(|a| a.get_item(2).ok())
            .and_then(|v| v.extract::<bool>().ok())
            .unwrap_or(false),
        error_type: args
            .as_ref()
            .and_then(|a| a.get_item(3).ok())
            .and_then(|v| v.extract::<String>().ok())
            .unwrap_or_default(),
    }
}

// Error types
pyo3::create_exception!(_spikard, BuildingFailedError, pyo3::exceptions::PyException);
pyo3::create_exception!(_spikard, SchemaError, pyo3::exceptions::PyException);

/// Convert a `spikard_graphql::SchemaError` error to a Python exception.
fn schema_error_to_py_err(e: spikard_graphql::SchemaError) -> pyo3::PyErr {
    let msg = e.to_string();
    #[allow(unreachable_patterns)]
    match &e {
        spikard_graphql::SchemaError::BuildingFailed(..) => BuildingFailedError::new_err(msg),
        spikard_graphql::SchemaError::ValidationError(..) => ValidationError::new_err(msg),
        spikard_graphql::SchemaError::ComplexityLimitExceeded { .. } => ComplexityLimitExceededError::new_err(msg),
        spikard_graphql::SchemaError::DepthLimitExceeded { .. } => DepthLimitExceededError::new_err(msg),
        _ => SchemaError::new_err(msg),
    }
}

